export function Avatar({ initials = "RK", className = "" }) {
  return (
    <div className={`h-9 w-9 rounded-full bg-[#4263EB] text-white flex items-center justify-center text-sm font-medium ${className}`}>
      {initials}
    </div>
  );
}

export function StatusDot({ color = "#51CF66", label = "Aktiv" }) {
  return (
    <span className="flex items-center gap-1.5 text-sm text-[#495057]">
      <span className="h-2 w-2 rounded-full" style={{ backgroundColor: color }} />
      {label}
    </span>
  );
}

export function SidebarNavigation({ items = ["Dashboard", "Berichte", "Ereignisse", "Einstellungen"], active = 0 }) {
  return (
    <nav className="w-56 rounded-lg border border-[#E9ECEF] bg-white p-3 space-y-1">
      {items.map((label, i) => (
        <div key={label} className={`rounded-md px-3 py-2 text-sm ${i === active ? "bg-[#EDF2FF] font-medium text-[#4263EB]" : "text-[#495057] hover:bg-[#F8F9FA]"}`}>
          {label}
        </div>
      ))}
    </nav>
  );
}

export function DonutChart({ title = "Kategorien" }) {
  return (
    <div className="rounded-lg border border-[#E9ECEF] bg-white p-4 w-56">
      <div className="text-sm font-medium text-[#212529] mb-3">{title}</div>
      <svg viewBox="0 0 42 42" className="h-28 w-28 mx-auto">
        <circle cx="21" cy="21" r="15.9" fill="none" stroke="#E9ECEF" strokeWidth="6" />
        <circle cx="21" cy="21" r="15.9" fill="none" stroke="#4263EB" strokeWidth="6" strokeDasharray="55 45" strokeDashoffset="25" />
        <circle cx="21" cy="21" r="15.9" fill="none" stroke="#51CF66" strokeWidth="6" strokeDasharray="25 75" strokeDashoffset="70" />
      </svg>
    </div>
  );
}

export function BarChart({ title = "Umsatz je Monat", values = [40, 65, 50, 85, 100] }) {
  return (
    <div className="rounded-lg border border-[#E9ECEF] bg-white p-4 w-64">
      <div className="text-sm font-medium text-[#212529] mb-3">{title}</div>
      <div className="flex items-end gap-2 h-24">
        {values.map((v, i) => (
          <div key={i} className="flex-1 rounded-t bg-[#4263EB]" style={{ height: `${v}%` }} />
        ))}
      </div>
    </div>
  );
}

export function DataTable({ rows = [["Deploy v2.1", "OK"], ["Import Lauf", "Läuft"]] }) {
  return (
    <div className="rounded-lg border border-[#E9ECEF] bg-white overflow-hidden">
      <table className="w-full text-sm">
        <thead>
          <tr className="bg-[#F8F9FA] text-left text-[#868E96]">
            <th className="px-3 py-2 font-medium">Ereignis</th>
            <th className="px-3 py-2 font-medium">Status</th>
          </tr>
        </thead>
        <tbody>
          {rows.map(([name, status]) => (
            <tr key={name} className="border-t border-[#F1F3F5]">
              <td className="px-3 py-2 text-[#212529]">{name}</td>
              <td className="px-3 py-2">{status}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export function Tooltip({ label = "Details anzeigen" }) {
  return (
    <div className="inline-flex flex-col items-center">
      <div className="rounded bg-[#1A1B1E] px-2 py-1 text-xs text-white">{label}</div>
      <div className="h-2 w-2 -mt-1 rotate-45 bg-[#1A1B1E]" />
    </div>
  );
}

export function SegmentedControl({ options = ["Woche", "Monat", "Jahr"], active = 0 }) {
  return (
    <div className="inline-flex rounded-lg bg-[#F1F3F5] p-1 text-sm">
      {options.map((o, i) => (
        <div key={o} className={`px-3 py-1 ${i === active ? "rounded-md bg-white font-medium text-[#212529] shadow-sm" : "text-[#868E96]"}`}>
          {o}
        </div>
      ))}
    </div>
  );
}

export function CategoryListItem({ label = "Marketing", value = "42%", color = "#4263EB" }) {
  return (
    <div className="flex items-center gap-3 rounded-lg border border-[#E9ECEF] bg-white px-3 py-2">
      <span className="h-2.5 w-2.5 rounded-full" style={{ backgroundColor: color }} />
      <span className="flex-1 text-sm text-[#212529]">{label}</span>
      <span className="text-sm font-medium text-[#212529]">{value}</span>
    </div>
  );
}

export function DashboardGridLayout({ children }) {
  return <div className="grid grid-cols-3 gap-3">{children}</div>;
}

export function MetricsOverview({ metrics = [{ label: "Umsatz", value: "€48.2k", delta: "+12%" }] }) {
  return (
    <div className="flex gap-3">
      {metrics.map((m) => (
        <div key={m.label} className="rounded-lg border border-[#E9ECEF] bg-white p-4 w-36">
          <div className="text-xs text-[#868E96]">{m.label}</div>
          <div className="text-xl font-semibold text-[#1A1B1E]">{m.value}</div>
          <div className="text-xs text-[#2B8A3E]">{m.delta}</div>
        </div>
      ))}
    </div>
  );
}

export function SidebarContentShell({ sidebar, children }) {
  return (
    <div className="flex gap-3">
      <div className="w-56 shrink-0">{sidebar}</div>
      <div className="flex-1 space-y-3">{children}</div>
    </div>
  );
}
